// ============================================================
// SOAR-003 — Code_TriagePhishing
// VERSION CORRIGÉE FINALE — headers token fix
// ============================================================

const SOC_TOKEN = String($vars.SOAR_PH_TOKEN || '').trim();
if (!SOC_TOKEN) {
  return [{ json: {
    error  : 'MISCONFIGURATION',
    message: 'SOAR_PH_TOKEN manquant en configuration n8n'
  }}];
}

var raw   = $input.first().json;
var input = raw;
var body  = raw.body || raw;
var now   = new Date().toISOString();

// ── TOKEN — lecture headers HTTP EN PRIORITÉ ──────────────
const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  input['x-soc-token'] ||
  input.soc_token      ||
  body['x-soc-token']  ||
  body.soc_token       || ''
).trim();

if (!receivedToken) {
  return [{ json: { error: 'UNAUTHORIZED', message: 'Token manquant', timestamp: now }}];
}
if (receivedToken !== SOC_TOKEN) {
  console.log('[SECURITY][SOAR-003] Token invalide — ' + now);
  return [{ json: { error: 'UNAUTHORIZED', message: 'Token SOC invalide — SOAR-003', timestamp: now }}];
}

// ── SANITISATION ───────────────────────────────────────────
function sanitizeForLog(val) {
  return String(val || '').replace(/[|\n\r\t<>]/g, '_').substring(0, 200);
}

function normalizeIP(raw_ip) {
  var s = String(raw_ip || '').trim().toLowerCase();
  if (s.startsWith('::ffff:')) return s.slice(7);
  if (/^(\d{1,3}\.){3}\d{1,3}$/.test(s)) {
    var octets = s.split('.').map(Number);
    if (octets.some(function(o) { return isNaN(o) || o < 0 || o > 255; })) return null;
    return octets.join('.');
  }
  if (/^[0-9a-f:]{3,39}$/.test(s)) return s;
  return null;
}

var rawIP    = body.source_ip || body.ip || input.source_ip || input.ip || '';
var sourceIP = normalizeIP(rawIP);
if (!sourceIP) {
  return [{ json: {
    error  : 'INVALID_IP',
    message: 'Format IP invalide: ' + sanitizeForLog(String(rawIP)),
    timestamp: now
  }}];
}

var PROTECTED_IPS = ['0.0.0.0', '127.0.0.1', '::1', '10.0.0.1', 'localhost'];
if (PROTECTED_IPS.includes(sourceIP)) {
  return [{ json: {
    error  : 'PROTECTED_IP',
    message: 'Triage refusé — IP protégée: ' + sourceIP,
    timestamp: now
  }}];
}

var incId    = sanitizeForLog(body.incident_id || input.incident_id || 'INC-PH-' + Date.now());
var username = sanitizeForLog(body.user || body.username || input.user || input.username || 'unknown');
var url      = sanitizeForLog(body.url || input.url || '');
var urlDisplay = url.length > 60 ? url.substring(0, 57) + '...' : url;

var SLA_MAP  = { P0: 15, P1: 30, P2: 120, P3: 480, P4: 1440 };
var priority = sanitizeForLog(body.priority || input.priority || 'P1');
var validPriorities = ['P0','P1','P2','P3','P4'];
if (!validPriorities.includes(priority)) priority = 'P1';

var sla_min   = SLA_MAP[priority] || 30;
var sla_due   = new Date(Date.now() + sla_min * 60000).toISOString();
var severity  = sanitizeForLog(body.severity || input.severity || 'HIGH');
var sev_score = Number(body.severity_score || input.severity_score || 75);
var mitre_tech   = sanitizeForLog(body.mitre_tech   || input.mitre_tech   || 'T1566');
var mitre_name   = sanitizeForLog(body.mitre_name   || input.mitre_name   || 'Phishing');
var mitre_tactic = sanitizeForLog(body.mitre_tactic || input.mitre_tactic || 'Initial Access');

var auditEntry = now + ' | TRIAGE | SOC_AUTO | Incident phishing reçu — IP: ' +
  sourceIP + ' — User: ' + username + ' — Priority: ' + priority;

var incident = {
  incident_id   : incId,
  incident_type : 'phishing',
  source_ip     : sourceIP,
  username      : username,
  user          : username,
  url           : url,
  url_display   : urlDisplay,
  mitre_tech    : mitre_tech,
  mitre_name    : mitre_name,
  mitre_tactic  : mitre_tactic,
  severity      : severity,
  severity_score: sev_score,
  priority      : priority,
  sla_minutes   : sla_min,
  sla_due       : sla_due,
  etat_siem     : sanitizeForLog(body.etat_siem || input.etat_siem || 'q3'),
  etat_soar     : 'q1_Triage',
  status        : 'TRIAGE',
  created_at    : now,
  audit_trail   : [auditEntry]
};

var store = $getWorkflowStaticData('global');
store['LAST_PHISHING_INCIDENT'] = incId;
store[incId] = JSON.stringify(incident);

console.log('[SOAR-003] Triage phishing: ' + incId + ' — User: ' + username + ' — IP: ' + sourceIP);

return [{ json: incident }];

// ============================================================
// SOAR-003 — Code_TraitementDecision Phishing
// ============================================================

var raw    = $input.first().json;
var body   = raw.body || raw;
var nowISO = new Date().toISOString();

// ── PARSE DÉCISION + OTP ──────────────────────────────────
var bodyRaw = String(
  body.Body || body.body || raw.Body || body.reponse || ''
).toUpperCase().trim();

const OTP_PATTERN = /^(PH)-(OUI|NON)-(\d{6})$/;
const match = bodyRaw.match(OTP_PATTERN);

if (!match) {
  return [{ json: {
    status : 'IGNORED',
    message: 'Format attendu: PH-OUI-123456 ou PH-NON-123456',
    received: bodyRaw, timestamp: nowISO
  }}];
}

const [, , decision, otpCode] = match;

// ── VALIDATION EXPÉDITEUR ──────────────────────────────────
var sender = String(
  body.From || body.from || raw.From || raw.from || ''
).replace('whatsapp:', '').trim();

if (!sender) {
  return [{ json: { error: 'MISSING_SENDER',
    message: 'Expéditeur non identifié', timestamp: nowISO } }];
}

var AUTHORIZED_PHONES = [];
if ($vars.ANALYST_L1_PHONE)
  AUTHORIZED_PHONES.push(String($vars.ANALYST_L1_PHONE).trim());
if ($vars.ANALYST_L2_PHONE)
  AUTHORIZED_PHONES.push(String($vars.ANALYST_L2_PHONE).trim());

if (AUTHORIZED_PHONES.length === 0) {
  return [{ json: { error: 'MISCONFIGURATION',
    message: 'ANALYST_L1_PHONE / ANALYST_L2_PHONE non configurés' } }];
}
if (!AUTHORIZED_PHONES.includes(sender)) {
  console.log('[SECURITY][SOAR-003] Expéditeur non autorisé: ' + sender);
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Expéditeur non autorisé', timestamp: nowISO } }];
}

var ANALYST_NAMES = {};
if ($vars.ANALYST_L1_PHONE)
  ANALYST_NAMES[String($vars.ANALYST_L1_PHONE).trim()] = 'SOC_L1_Analyst';
if ($vars.ANALYST_L2_PHONE)
  ANALYST_NAMES[String($vars.ANALYST_L2_PHONE).trim()] = 'SOC_L2_Lead';
var analystName = ANALYST_NAMES[sender] || 'SOC_L1_Analyst';

// ── VALIDATION OTP DEPUIS SUPABASE ────────────────────────
// Lire le résultat du nœud DB_ValidateOTP_PH
var otpRow = null;
try {
  const dbResult = $('DB_ValidateOTP_PH').first()?.json;
  if (dbResult && dbResult.otp_code) {
    otpRow = dbResult;
  }
} catch(e) {
  console.log('[SOAR-003] Impossible de lire DB_ValidateOTP_PH: ' + e.message);
}

if (!otpRow) {
  console.log('[SECURITY][SOAR-003] OTP invalide ou expiré: ' + otpCode.substring(0,3) + '***');
  return [{ json: {
    error    : 'INVALID_OTP',
    message  : 'OTP invalide, expiré, ou déjà utilisé',
    timestamp: nowISO
  }}];
}

const incidentId = otpRow.incident_id;

// ── LECTURE INCIDENT DEPUIS STORE (avec fallback) ─────────
var store = $getWorkflowStaticData('global');
var incidentData = {};
try { incidentData = JSON.parse(store[incidentId] || '{}'); }
catch(e) { incidentData = {}; }

if (!incidentData.incident_id) {
  console.log('[SOAR-003][WARN] Store vide pour: ' + incidentId +
    ' — reconstruction depuis contexte');
  incidentData = {
    incident_id   : incidentId,
    incident_type : 'phishing',
    source_ip     : String(body.source_ip || raw.source_ip || '0.0.0.0'),
    username      : String(body.username || body.user || raw.username || 'unknown'),
    user          : String(body.user || body.username || raw.user || 'unknown'),
    url           : String(body.url || raw.url || ''),
    mitre_tech    : String(body.mitre_tech || raw.mitre_tech || 'T1566'),
    mitre_name    : String(body.mitre_name || raw.mitre_name || 'Phishing'),
    mitre_tactic  : String(body.mitre_tactic || raw.mitre_tactic || 'Initial Access'),
    severity      : String(body.severity || raw.severity || 'HIGH'),
    severity_score: Number(body.severity_score || raw.severity_score || 75),
    priority      : String(body.priority || raw.priority || 'P1'),
    sla_minutes   : Number(body.sla_minutes || raw.sla_minutes || 30),
    audit_trail   : [],
    created_at    : new Date(Date.now() - 300000).toISOString()
  };
}

function sanitizeForLog(val) {
  return String(val).replace(/[|\n\r\t]/g, '_').substring(0, 100);
}

var trail = Array.isArray(incidentData.audit_trail)
  ? incidentData.audit_trail : [];
trail.push(
  nowISO + ' | DECISION | ' + sanitizeForLog(analystName) +
  ' | Réponse: ' + sanitizeForLog(decision) +
  ' | OTP: ' + otpCode.substring(0, 3) + '***'
);

delete store['LAST_PHISHING_INCIDENT'];

return [{ json: {
  incident_id   : incidentData.incident_id,
  incident_type : 'phishing',
  source_ip     : incidentData.source_ip,
  username      : incidentData.username,
  user          : incidentData.user || incidentData.username,
  url           : incidentData.url,
  url_display   : String(incidentData.url || '').substring(0, 60),
  mitre_tech    : incidentData.mitre_tech,
  mitre_name    : incidentData.mitre_name,
  mitre_tactic  : incidentData.mitre_tactic,
  severity      : incidentData.severity,
  severity_score: incidentData.severity_score,
  priority      : incidentData.priority,
  sla_minutes   : incidentData.sla_minutes,
  decided_by    : analystName,
  decided_at    : nowISO,
  decision,
  otp_code      : otpCode,
  is_approved   : (decision === 'OUI'),
  audit_trail   : trail
}}];

