// ============================================================
// SOAR-003 — Code_GenerateOTP_PH
// ============================================================

var input = $input.first().json;
var now   = new Date().toISOString();

var incidentId = String(input.incident_id || '').trim();
var phone      = String($vars.ANALYST_L1_PHONE || '').trim();

if (!incidentId) {
  return [{ json: {
    error    : 'MISSING_INCIDENT_ID',
    message  : 'incident_id manquant — impossible de générer OTP',
    timestamp: now
  }}];
}

var supabaseOtpUrl = String($vars.SUPABASE_OTP_URL || '').trim();
var otpEdgeToken   = String($vars.OTP_EDGE_TOKEN   || '').trim();

if (!supabaseOtpUrl || !otpEdgeToken) {
  // FALLBACK DÉGRADÉ — math.random() multi-source
  console.log('[SOAR-003][WARN] Edge Function non configurée — fallback Math.random');

  var t1 = Date.now();
  var t2 = new Date().getMilliseconds();
  var r1 = Math.random(); var r2 = Math.random();
  var r3 = Math.random(); var r4 = Math.random(); var r5 = Math.random();

  var raw = Math.abs(
    Math.floor(t1 % 1000000 * r1) ^
    Math.floor(t2 * 997 * r2)     ^
    Math.floor(r3 * 0xFFFFFF)     ^
    Math.floor(r4 * 0xFFFFF)      ^
    Math.floor(r5 * 0xFFFFF + t1 % 100)
  );
  var otpFallback = String((raw % 900000) + 100000).substring(0, 6);
  if (!/^\d{6}$/.test(otpFallback)) otpFallback = String(100000 + Math.floor(Math.random() * 899999));

  var expiresFallback = new Date(Date.now() + 5 * 60 * 1000).toISOString();

  // Sauvegarder en store pour Code_TraitementDecision
  var store = $getWorkflowStaticData('global');
  store['LAST_PHISHING_INCIDENT'] = incidentId;
  store[incidentId] = JSON.stringify(input);

  return [{ json: buildPHOutput(input, otpFallback, expiresFallback, now, true) }];
}

// Sauvegarder en store pour Code_TraitementDecision
var store = $getWorkflowStaticData('global');
store['LAST_PHISHING_INCIDENT'] = incidentId;
store[incidentId] = JSON.stringify(input);

// Mode normal : préparer le payload pour HTTP_GenerateOTP_PH
return [{ json: {
  _incident_data : input,
  _otp_request   : { incident_id: incidentId, phone: phone },
  _edge_url      : supabaseOtpUrl,
  _edge_token    : otpEdgeToken,
  timestamp      : now
}}];

function buildPHOutput(inc, otpCode, expiresAt, ts, isFallback) {
  var urlDisplay = String(inc.url || '');
  if (urlDisplay.length > 60) urlDisplay = urlDisplay.substring(0, 57) + '...';

  return {
    incident_id    : inc.incident_id,
    source_ip      : inc.source_ip,
    username       : inc.username,
    user           : inc.user || inc.username,
    url            : inc.url,
    url_display    : urlDisplay,
    mitre_tech     : inc.mitre_tech,
    mitre_name     : inc.mitre_name,
    mitre_tactic   : inc.mitre_tactic,
    severity       : inc.severity,
    severity_score : inc.severity_score,
    priority       : inc.priority,
    sla_minutes    : inc.sla_minutes,
    sla_due        : inc.sla_due,
    audit_trail    : inc.audit_trail,
    etat_soar      : inc.etat_soar,
    otp_code       : otpCode,
    otp_expires_at : expiresAt,
    otp_fallback   : isFallback || false,
    first_alert_at : ts,
    whatsapp_message:
      '🎣 INCIDENT PHISHING — ' + (inc.incident_id || 'INC-???') + '\n' +
      '━━━━━━━━━━━━━━━━━━━━━━━━\n' +
      '🛡️  MITRE    : ' + (inc.mitre_tech || 'T1566') + ' — ' + (inc.mitre_name || 'Phishing') + '\n' +
      '👤 Utilisateur: ' + (inc.user || inc.username || 'inconnu') + '\n' +
      '🔗 URL        : ' + (urlDisplay || 'N/A') + '\n' +
      '⚡ Sévérité   : ' + (inc.severity || 'HIGH') + ' (' + (inc.severity_score || 75) + '/100)\n' +
      '🔴 Priorité   : ' + (inc.priority || 'P1') + '\n' +
      '⏰ SLA        : ' + (inc.sla_minutes || 30) + ' min\n' +
      '━━━━━━━━━━━━━━━━━━━━━━━━\n' +
      '➤ CONTENIR : répondez PH-OUI-' + otpCode + '\n' +
      '➤ ESCALADER: répondez PH-NON-' + otpCode + '\n' +
      '⏰ Code valide 5 minutes uniquement'
  };
}
